def test_access_service_extract_api_key_trims_authorization_and_header_tokens() -> None:
    service = AccessService.__new__(AccessService)

    assert service.extract_api_key({"authorization": "  Bearer remote-key  "}) == "remote-key"
    assert service.extract_api_key({"X-OpenClaw-Token": "  remote-key  "}) == "remote-key"
    assert service.extract_api_key({"X-OpenZues-Key": "   "}) is None


def test_access_service_extract_api_key_prefers_bearer_over_header_fallback() -> None:
    service = AccessService.__new__(AccessService)

    assert service.extract_api_key(
        {
            "authorization": "Bearer bearer-token",
            "X-OpenClaw-Token": "header-token",
        }
    ) == "bearer-token"
    assert service.extract_api_key(
        {
            "authorization": "Basic ignored",
            "X-OpenClaw-Token": "header-token",
        }
    ) == "header-token"
    assert service.extract_api_key({"X-OpenClaw-Token": "header-token"}) == "header-token"
    assert service.extract_api_key({}) is None


class FakeNodeConnection:
    def __init__(self, conn_id: str) -> None:
        self.conn_id = conn_id
        self.sent_events: list[dict[str, object | None]] = []

    def send_gateway_event(self, event: str, payload: object) -> None:
        self.sent_events.append({"event": event, "payload": payload})


class AutoReplyNodeConnection(FakeNodeConnection):
    def __init__(self, registry: GatewayNodeRegistry, conn_id: str) -> None:
        super().__init__(conn_id)
        self.registry = registry

    def send_gateway_event(self, event: str, payload: object) -> None:
        super().send_gateway_event(event, payload)
        if event != "node.invoke.request" or not isinstance(payload, dict):
            return
        request_id = str(payload.get("id") or "")
        node_id = str(payload.get("nodeId") or "")
        if not request_id or not node_id:
            return
        asyncio.get_running_loop().call_soon(
            lambda: self.registry.handle_invoke_result(
                request_id=request_id,
                node_id=node_id,
                ok=True,
                payload={"status": "done"},
                payload_json='{"status":"done"}',
                error=None,
            )
        )


class BackgroundUnavailableNodeConnection(FakeNodeConnection):
    def __init__(self, registry: GatewayNodeRegistry, conn_id: str) -> None:
        super().__init__(conn_id)
        self.registry = registry

    def send_gateway_event(self, event: str, payload: object) -> None:
        super().send_gateway_event(event, payload)
        if event != "node.invoke.request" or not isinstance(payload, dict):
            return
        request_id = str(payload.get("id") or "")
        node_id = str(payload.get("nodeId") or "")
        if not request_id or not node_id:
            return
        asyncio.get_running_loop().call_soon(
            lambda: self.registry.handle_invoke_result(
                request_id=request_id,
                node_id=node_id,
                ok=False,
                payload=None,
                payload_json=None,
                error={
                    "code": "NODE_BACKGROUND_UNAVAILABLE",
                    "message": (
                        "NODE_BACKGROUND_UNAVAILABLE: canvas/camera/screen commands "
                        "require foreground"
                    ),
                },
            )
        )


