def _json_conversation_target(payload: TaskBlueprintCreate) -> dict[str, object] | None:
    return (
        payload.conversation_target.model_dump(mode="json")
        if payload.conversation_target is not None
        else None
    )


async def _create_scheduled_mission(
    database: Database,
    *,
    name: str,
    objective: str,
    status: str,
    task_blueprint_id: int,
    thread_id: str,
    session_key: str = "launch:mode:workspace_affinity",
    last_checkpoint: str | None = None,
    last_error: str | None = None,
    model: str = "gpt-5.4",
) -> int:
    mission_id = await database.create_mission(
        name=name,
        objective=objective,
        status=status,
        instance_id=7,
        project_id=None,
        thread_id=thread_id,
        session_key=session_key,
        conversation_target=None,
        cwd="C:/workspace",
        model=model,
        reasoning_effort=None,
        collaboration_mode=None,
        max_turns=None,
        use_builtin_agents=True,
        run_verification=True,
        auto_commit=False,
        pause_on_approval=True,
        allow_auto_reflexes=True,
        auto_recover=True,
        auto_recover_limit=2,
        reflex_cooldown_seconds=900,
        allow_failover=True,
        toolsets=[],
        task_blueprint_id=task_blueprint_id,
    )
    updates: dict[str, object] = {}
    if last_checkpoint is not None:
        updates["last_checkpoint"] = last_checkpoint
    if last_error is not None:
        updates["last_error"] = last_error
    if updates:
        await database.update_mission(mission_id, **updates)
    return mission_id


