@pytest.mark.asyncio
async def test_voicewake_methods_surface_defaults_persist_updates_and_broadcast(
    tmp_path,
) -> None:
    registry = GatewayNodeRegistry()
    connection = FakeNodeConnection("conn-voicewake-node-1")
    registry.register(
        connection,
        GatewayNodeConnect(
            client_id="live-voicewake-node-1",
            device_id="voicewake-node-1",
            platform="ios",
        ),
    )

    class _RecordingBroadcastHub(BroadcastHub):
        def __init__(self) -> None:
            super().__init__()
            self.published_events: list[dict[str, object]] = []

        async def publish(self, event: dict[str, object]) -> None:
            self.published_events.append(dict(event))
            await super().publish(event)

    hub = _RecordingBroadcastHub()
    service = GatewayNodeMethodService(
        registry,
        hub=hub,
        voicewake_service=GatewayVoiceWakeService(tmp_path),
    )

    initial = await service.call("voicewake.get", {})

    async with hub.subscribe() as queue:
        updated = await service.call(
            "voicewake.set",
            {"triggers": ["  hello  ", "", "world  "]},
            now_ms=1234,
        )
        published = await asyncio.wait_for(queue.get(), timeout=1)

    reloaded = await service.call("voicewake.get", {})

    assert initial == {"triggers": ["openclaw", "claude"]}
    assert updated == {"triggers": ["hello", "world"]}
    assert reloaded == {"triggers": ["hello", "world"]}
    assert connection.sent_events[-1] == {
        "event": "voicewake.changed",
        "payload": {"triggers": ["hello", "world"]},
    }
    assert published["type"] == "gateway_event"
    assert published["event"] == "voicewake.changed"
    assert published["payload"] == {"triggers": ["hello", "world"]}
    assert isinstance(published["createdAt"], str)


@pytest.mark.asyncio
async def test_talk_mode_persists_updates_and_broadcast(tmp_path) -> None:
    registry = GatewayNodeRegistry()
    connection = FakeNodeConnection("conn-talk-mode-node-1")
    registry.register(
        connection,
        GatewayNodeConnect(
            client_id="live-talk-mode-node-1",
            device_id="talk-mode-node-1",
            platform="ios",
        ),
    )

    class _RecordingBroadcastHub(BroadcastHub):
        def __init__(self) -> None:
            super().__init__()
            self.published_events: list[dict[str, object]] = []

        async def publish(self, event: dict[str, object]) -> None:
            self.published_events.append(dict(event))
            await super().publish(event)

    hub = _RecordingBroadcastHub()
    service = GatewayNodeMethodService(
        registry,
        hub=hub,
        talk_mode_service=GatewayTalkModeService(tmp_path),
    )

    async with hub.subscribe() as queue:
        updated = await service.call(
            "talk.mode",
            {"enabled": True, "phase": "listening"},
            now_ms=1234,
        )
        published = await asyncio.wait_for(queue.get(), timeout=1)

    reloaded = GatewayTalkModeService(tmp_path).load()

    assert updated == {
        "enabled": True,
        "phase": "listening",
    }
    assert reloaded.enabled is True
    assert reloaded.phase == "listening"
    assert connection.sent_events[-1] == {
        "event": "talk.mode",
        "payload": {
            "enabled": True,
            "phase": "listening",
        },
    }
    assert published["type"] == "gateway_event"
    assert published["event"] == "talk.mode"
    assert published["payload"] == {
        "enabled": True,
        "phase": "listening",
    }
    assert isinstance(published["createdAt"], str)


@pytest.mark.asyncio
async def test_gateway_identity_get_returns_stable_persisted_device_identity(tmp_path) -> None:
    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        gateway_identity_service=GatewayIdentityService(tmp_path),
    )

    first = await service.call("gateway.identity.get", {})
    second = await service.call("gateway.identity.get", {})

    assert first == second
    assert re.fullmatch(r"[0-9a-f]{64}", first["id"])
    assert isinstance(first["publicKey"], str)
    assert re.fullmatch(r"[A-Za-z0-9_-]{43}", first["publicKey"])
    assert len(first["publicKey"]) > 20
    identity_path = tmp_path / "settings" / "gateway-identity.json"
    assert identity_path.exists()
    stored = json.loads(identity_path.read_text(encoding="utf-8"))
    assert stored["version"] == 1
    assert stored["deviceId"] == first["id"]
    assert "BEGIN PUBLIC KEY" in stored["publicKeyPem"]
    assert "BEGIN PRIVATE KEY" in stored["privateKeyPem"]
    assert isinstance(stored["createdAtMs"], int)


@pytest.mark.asyncio
async def test_gateway_identity_get_repairs_mismatched_openclaw_device_id(tmp_path) -> None:
    private_key = Ed25519PrivateKey.generate()
    public_key_bytes = private_key.public_key().public_bytes(
        encoding=serialization.Encoding.Raw,
        format=serialization.PublicFormat.Raw,
    )
    expected_id = hashlib.sha256(public_key_bytes).hexdigest()
    expected_public_key = base64.urlsafe_b64encode(public_key_bytes).decode("ascii").rstrip("=")
    identity_path = tmp_path / "settings" / "gateway-identity.json"
    identity_path.parent.mkdir(parents=True, exist_ok=True)
    identity_path.write_text(
        json.dumps(
            {
                "version": 1,
                "deviceId": "stale-device-id",
                "publicKeyPem": private_key.public_key()
                .public_bytes(
                    encoding=serialization.Encoding.PEM,
                    format=serialization.PublicFormat.SubjectPublicKeyInfo,
                )
                .decode("utf-8"),
                "privateKeyPem": private_key.private_bytes(
                    encoding=serialization.Encoding.PEM,
                    format=serialization.PrivateFormat.PKCS8,
                    encryption_algorithm=serialization.NoEncryption(),
                ).decode("utf-8"),
                "createdAtMs": 123,
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        gateway_identity_service=GatewayIdentityService(tmp_path),
    )

    payload = await service.call("gateway.identity.get", {})
    stored = json.loads(identity_path.read_text(encoding="utf-8"))

    assert payload == {"id": expected_id, "publicKey": expected_public_key}
    assert stored["deviceId"] == expected_id
    assert stored["createdAtMs"] == 123


@pytest.mark.asyncio
async def test_gateway_identity_get_repairs_device_id_from_public_key_even_with_invalid_private_pem(
    tmp_path: Path,
) -> None:
    private_key = Ed25519PrivateKey.generate()
    public_key_pem = private_key.public_key().public_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PublicFormat.SubjectPublicKeyInfo,
    ).decode("utf-8")
    public_key_bytes = private_key.public_key().public_bytes(
        encoding=serialization.Encoding.Raw,
        format=serialization.PublicFormat.Raw,
    )
    expected_id = hashlib.sha256(public_key_bytes).hexdigest()
    expected_public_key = base64.urlsafe_b64encode(public_key_bytes).decode("ascii").rstrip("=")
    identity_path = tmp_path / "settings" / "gateway-identity.json"
    identity_path.parent.mkdir(parents=True, exist_ok=True)
    identity_path.write_text(
        json.dumps(
            {
                "version": 1,
                "deviceId": "stale-device-id",
                "publicKeyPem": public_key_pem,
                "privateKeyPem": "not-a-valid-private-key",
                "createdAtMs": 123,
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        gateway_identity_service=GatewayIdentityService(tmp_path),
    )

    payload = await service.call("gateway.identity.get", {})
    stored = json.loads(identity_path.read_text(encoding="utf-8"))

    assert payload == {"id": expected_id, "publicKey": expected_public_key}
    assert stored["deviceId"] == expected_id
    assert stored["publicKeyPem"] == public_key_pem
    assert stored["privateKeyPem"] == "not-a-valid-private-key"
    assert stored["createdAtMs"] == 123


