@pytest.mark.asyncio
async def test_config_schema_lookup_supports_array_paths_and_rejects_invalid_lookup_paths() -> None:
    service = GatewayNodeMethodService(GatewayNodeRegistry())

    array_lookup = await service.call(
        "config.schema.lookup",
        {"path": "localMediaPreviewRoots"},
    )
    indexed_lookup = await service.call(
        "config.schema.lookup",
        {"path": "localMediaPreviewRoots[0]"},
    )
    wildcard_lookup = await service.call(
        "config.schema.lookup",
        {"path": "localMediaPreviewRoots[*]"},
    )

    assert array_lookup == {
        "path": "localMediaPreviewRoots",
        "schema": {
            "type": "array",
            "title": "Local Media Preview Roots",
        },
        "hint": {"label": "Local Media Preview Roots"},
        "hintPath": "localMediaPreviewRoots",
        "children": [
            {
                "key": "*",
                "path": "localMediaPreviewRoots.*",
                "type": "string",
                "required": False,
                "hasChildren": False,
                "hint": {"label": "Local Media Preview Root"},
                "hintPath": "localMediaPreviewRoots[]",
            }
        ],
    }

    assert indexed_lookup == {
        "path": "localMediaPreviewRoots.0",
        "schema": {
            "type": "string",
            "title": "Local Media Preview Root",
        },
        "hint": {"label": "Local Media Preview Root"},
        "hintPath": "localMediaPreviewRoots[]",
        "children": [],
    }
    assert wildcard_lookup == {
        "path": "localMediaPreviewRoots.*",
        "schema": {
            "type": "string",
            "title": "Local Media Preview Root",
        },
        "hint": {"label": "Local Media Preview Root"},
        "hintPath": "localMediaPreviewRoots[]",
        "children": [],
    }
    embed_lookup = await service.call(
        "config.schema.lookup",
        {"path": "embedSandbox"},
    )
    assert embed_lookup == {
        "path": "embedSandbox",
        "schema": {
            "type": "string",
            "title": "Embed Sandbox",
            "enum": ["strict", "scripts", "trusted"],
        },
        "hint": {"label": "Embed Sandbox"},
        "hintPath": "embedSandbox",
        "children": [],
    }

    for path in [".", "...", "", "   ", "gateway.auth\nspoof", "gateway." + ("a" * 1020)]:
        with pytest.raises(ValueError, match="config schema path not found"):
            await service.call("config.schema.lookup", {"path": path})


