async def test_chat_send_effective_attachments_fail_as_unavailable_runtime(
    attachments: list[dict[str, object]],
) -> None:
    async def fake_chat_send_service(
        *,
        session_key: str,
        message: str,
        idempotency_key: str,
        thinking: str | None,
        deliver: bool | None,
        timeout_ms: int | None,
    ) -> dict[str, object]:
        del session_key, message, idempotency_key, thinking, deliver, timeout_ms
        return {"runId": "unused", "status": "ok"}

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        chat_send_service=fake_chat_send_service,
    )

    with pytest.raises(GatewayNodeMethodError) as exc_info:
        await service.call(
            "chat.send",
            {
                "sessionKey": "openzues:thread:demo",
                "message": "status",
                "attachments": attachments,
                "idempotencyKey": "run-chat-send-effective-attachments-1",
            },
        )

    assert exc_info.value.code == "UNAVAILABLE"
    assert exc_info.value.status_code == 503
    assert exc_info.value.message == (
        "chat.send attachments are unavailable until control chat attachment runtime is wired"
    )


@pytest.mark.asyncio
async def test_chat_send_uses_attachment_runtime_when_wired() -> None:
    observed: dict[str, object | None] = {}
    attachments = [
        {
            "type": "image",
            "mimeType": "image/png",
            "fileName": "preview.png",
            "content": "Zm9v",
        }
    ]

    async def fake_chat_send_service(
        *,
        session_key: str,
        message: str,
        idempotency_key: str,
        thinking: str | None,
        deliver: bool | None,
        timeout_ms: int | None,
    ) -> dict[str, object]:
        del session_key, message, idempotency_key, thinking, deliver, timeout_ms
        raise AssertionError("text-only chat runtime should not handle effective attachments")

    async def fake_attachment_send_service(
        *,
        session_key: str,
        message: str,
        idempotency_key: str,
        thinking: str | None,
        deliver: bool | None,
        timeout_ms: int | None,
        attachments: list[dict[str, object]],
        channel: str | None = None,
        to: str | None = None,
        node_id: str | None = None,
    ) -> dict[str, object]:
        observed.update(
            {
                "session_key": session_key,
                "message": message,
                "idempotency_key": idempotency_key,
                "thinking": thinking,
                "deliver": deliver,
                "timeout_ms": timeout_ms,
                "attachments": attachments,
                "channel": channel,
                "to": to,
                "node_id": node_id,
            }
        )
        return {"runId": idempotency_key, "status": "ok"}

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        chat_send_service=fake_chat_send_service,
        chat_attachment_send_service=fake_attachment_send_service,
    )

    payload = await service.call(
        "chat.send",
        {
            "sessionKey": "openzues:thread:demo",
            "message": "Inspect this image.",
            "thinking": "medium",
            "deliver": True,
            "timeoutMs": 45_000,
            "attachments": attachments,
            "idempotencyKey": "run-chat-send-attachment-runtime-1",
        },
    )

    assert payload == {"runId": "run-chat-send-attachment-runtime-1", "status": "ok"}
    assert observed == {
        "session_key": "openzues:thread:demo",
        "message": "Inspect this image.",
        "idempotency_key": "run-chat-send-attachment-runtime-1",
        "thinking": "medium",
        "deliver": True,
        "timeout_ms": 45_000,
        "attachments": attachments,
        "channel": None,
        "to": None,
        "node_id": None,
    }


