@pytest.mark.asyncio
async def test_logs_tail_returns_latest_workspace_log_lines(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.chdir(tmp_path)
    logs_root = tmp_path / "logs"
    logs_root.mkdir(parents=True, exist_ok=True)
    older = logs_root / "openzues-older.log"
    newer = logs_root / "openzues-newer.log"
    older.write_text("old line\n", encoding="utf-8")
    newer.write_text("new line\n", encoding="utf-8")
    os.utime(older, (1, 1))
    os.utime(newer, None)

    service = GatewayNodeMethodService(GatewayNodeRegistry())
    payload = await service.call(
        "logs.tail",
        {
            "limit": 10,
            "maxBytes": 1_000,
        },
    )

    assert payload == {
        "file": str(newer),
        "cursor": newer.stat().st_size,
        "size": newer.stat().st_size,
        "lines": ["new line"],
        "truncated": False,
        "reset": False,
    }


@pytest.mark.asyncio
async def test_logs_tail_redacts_sensitive_tokens_from_returned_lines(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.chdir(tmp_path)
    logs_root = tmp_path / "logs"
    logs_root.mkdir(parents=True, exist_ok=True)
    log_file = logs_root / "openzues-sensitive.log"
    raw_line = (
        "starting --hook-token hook-token-aaaaaaaaaaaaaaaaaaaa "
        "OPENAI_API_KEY=sk-1234567890abcdef "
        "ghp_1234567890abcdefghijklmn "
        "Authorization: Bearer abcdef1234567890ghij\n"
    )
    log_file.write_text(raw_line, encoding="utf-8")

    service = GatewayNodeMethodService(GatewayNodeRegistry())
    payload = await service.call(
        "logs.tail",
        {
            "limit": 10,
            "maxBytes": 1_000,
        },
    )

    assert payload["file"] == str(log_file)
    lines = payload["lines"]
    assert isinstance(lines, list)
    assert len(lines) == 1
    line = lines[0]
    assert isinstance(line, str)
    assert line != raw_line.strip()
    assert "hook-token-aaaaaaaaaaaaaaaaaaaa" not in line
    assert "sk-1234567890abcdef" not in line
    assert "ghp_1234567890abcdefghijklmn" not in line
    assert "abcdef1234567890ghij" not in line
    assert "--hook-token " in line
    assert "OPENAI_API_KEY=" in line
    assert "Authorization: Bearer " in line


@pytest.mark.asyncio
async def test_update_run_returns_openclaw_envelope_sentinel_and_timeout_minimum(
    tmp_path,
) -> None:
    view: dict[str, object] = {
        "headline": "Runtime self-update is watching the repo",
        "summary": "The current process is aligned with the checked-out repo revision.",
        "enabled": True,
        "repo_root": "C:/workspace/OpenZues",
        "startup_revision": "rev-a",
        "current_revision": "rev-b",
        "pending_revision": "rev-b",
        "pending_restart": True,
        "restart_in_progress": False,
        "safe_to_restart": False,
        "last_checked_at": "2026-04-29T12:00:00Z",
        "last_restart_at": None,
        "last_error": None,
        "auto_restart": True,
    }
    tick_calls: list[str] = []

    async def fake_tick() -> bool:
        tick_calls.append("tick")
        return False

    async def fake_view() -> dict[str, object]:
        return dict(view)

    database = Database(tmp_path / "openzues.db")
    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        database=database,
        runtime_update_tick=fake_tick,
        runtime_update_view=fake_view,
    )
    payload = await service.call(
        "update.run",
        {
            "timeoutMs": 1,
            "sessionKey": "agent:main:slack:channel:C0123ABC:thread:1234567890.123456",
            "deliveryContext": {
                "channel": "slack",
                "to": "slack:C0123ABC",
                "accountId": "workspace-1",
            },
            "note": "Apply the runtime update.",
        },
    )

    assert tick_calls == ["tick"]
    assert payload["ok"] is True
    assert payload["restart"] is None
    result = payload["result"]
    assert isinstance(result, dict)
    assert result["status"] == "ok"
    assert result["mode"] == "openzues-runtime"
    assert result["timeoutMs"] == 1000
    assert result["snapshot"] == view
    sentinel = payload["sentinel"]
    assert isinstance(sentinel, dict)
    sentinel_path = sentinel["path"]
    assert isinstance(sentinel_path, str)
    assert Path(sentinel_path).exists()
    sentinel_payload = sentinel["payload"]
    assert isinstance(sentinel_payload, dict)
    assert sentinel_payload["kind"] == "update"
    assert sentinel_payload["status"] == "ok"
    assert sentinel_payload["sessionKey"] == (
        "agent:main:slack:channel:C0123ABC:thread:1234567890.123456"
    )
    assert sentinel_payload["threadId"] == "1234567890.123456"
    assert sentinel_payload["deliveryContext"] == {
        "channel": "slack",
        "to": "slack:C0123ABC",
        "accountId": "workspace-1",
    }
    assert sentinel_payload["message"] == "Apply the runtime update."
    assert sentinel_payload["stats"]["mode"] == "openzues-runtime"


