@pytest.mark.asyncio
async def test_wizard_methods_drive_bounded_gateway_wizard_runtime() -> None:
    state: dict[str, object] = {
        "mode": "local",
        "project_path": None,
        "task_name": None,
    }

    async def load_session() -> dict[str, object]:
        return dict(state)

    async def save_session(patch: dict[str, object]) -> dict[str, object]:
        state.update(patch)
        return dict(state)

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        wizard_service=GatewayWizardService(
            load_session=load_session,
            save_session=save_session,
        ),
    )

    start = await service.call(
        "wizard.start",
        {"mode": "remote", "workspace": "C:/workspace/OpenZues"},
    )
    session_id = start["sessionId"]
    step = start["step"]

    assert isinstance(session_id, str)
    assert start["done"] is False
    assert start["status"] == "running"
    assert step == {
        "id": step["id"],
        "field": "operator_name",
        "type": "text",
        "title": "Operator Name",
        "message": "Name the operator who should receive the remote ingress API key.",
        "executor": "client",
        "placeholder": "Remote Builder",
    }

    status = await service.call("wizard.status", {"sessionId": session_id})
    assert status == {"status": "running"}

    next_step = await service.call(
        "wizard.next",
        {
            "sessionId": session_id,
            "answer": {
                "stepId": step["id"],
                "value": "Remote Builder",
            },
        },
    )

    assert next_step == {
        "done": False,
        "status": "running",
        "step": {
            "id": next_step["step"]["id"],
            "field": "operator_email",
            "type": "text",
            "title": "Operator Email",
            "message": "Optionally add an email for the remote API key handoff.",
            "executor": "client",
            "placeholder": "builder@example.com",
            "required": False,
            "inputType": "email",
        },
    }

    team_step = await service.call(
        "wizard.next",
        {
            "sessionId": session_id,
            "answer": {
                "stepId": next_step["step"]["id"],
                "value": "",
            },
        },
    )
    assert team_step["step"]["field"] == "team_name"

    note_step = await service.call(
        "wizard.next",
        {
            "sessionId": session_id,
            "answer": {
                "stepId": team_step["step"]["id"],
                "value": "",
            },
        },
    )
    assert note_step["step"]["field"] == "remote_lane_note"

    task_step = await service.call(
        "wizard.next",
        {
            "sessionId": session_id,
            "answer": {
                "stepId": note_step["step"]["id"],
                "value": True,
            },
        },
    )
    assert task_step["step"]["field"] == "task_name"

    done = await service.call(
        "wizard.next",
        {
            "sessionId": session_id,
            "answer": {
                "stepId": task_step["step"]["id"],
                "value": "Parity Loop",
            },
        },
    )

    assert done == {"done": True, "status": "done"}
    assert state == {
        "flow": "advanced",
        "instance_id": None,
        "instance_mode": "existing",
        "instance_name": "Local Codex Desktop",
        "mode": "remote",
        "operator_email": None,
        "operator_name": "Remote Builder",
        "project_path": "C:/workspace/OpenZues",
        "team_name": None,
        "task_name": "Parity Loop",
    }

    with pytest.raises(ValueError, match="wizard not found"):
        await service.call("wizard.status", {"sessionId": session_id})


@pytest.mark.asyncio
async def test_wizard_cancel_discards_unapplied_draft() -> None:
    state: dict[str, object] = {
        "mode": "local",
        "project_path": None,
        "task_name": None,
    }

    async def load_session() -> dict[str, object]:
        return dict(state)

    async def save_session(patch: dict[str, object]) -> dict[str, object]:
        state.update(patch)
        return dict(state)

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        wizard_service=GatewayWizardService(
            load_session=load_session,
            save_session=save_session,
        ),
    )

    start = await service.call("wizard.start", {})
    session_id = start["sessionId"]

    assert start["done"] is False
    assert start["status"] == "running"
    assert start["step"] == {
        "id": start["step"]["id"],
        "field": "flow",
        "type": "select",
        "title": "Setup Flow",
        "message": "Choose how deeply to stage the local bootstrap posture.",
        "options": [
            {
                "value": "quickstart",
                "label": "QuickStart",
                "hint": "Reuse the current control plane and tune the rest later.",
            },
            {
                "value": "advanced",
                "label": "Advanced",
                "hint": "Stage the full local control plane posture before bootstrap.",
            },
        ],
        "executor": "client",
        "initialValue": "quickstart",
    }

    cancel = await service.call("wizard.cancel", {"sessionId": session_id})

    assert cancel == {"status": "cancelled", "error": "cancelled"}
    assert state == {
        "mode": "local",
        "project_path": None,
        "task_name": None,
    }


