def test_browser_act_args_maps_bounded_action_subset() -> None:
    assert browser_act_args("click", {"kind": "click", "ref": "@e1"}) == ["click", "@e1"]
    assert browser_act_args("wait", {"kind": "wait", "timeMs": 250}) == ["wait", "250"]
    assert browser_act_args("type", {"kind": "type", "text": "hello"}) == [
        "keyboard",
        "type",
        "hello",
    ]
    assert browser_act_args("resize", {"kind": "resize", "width": 800, "height": 600}) == [
        "set",
        "viewport",
        "800",
        "600",
    ]
    assert browser_act_args("dblclick", {"kind": "dblclick", "selector": "#save"}) == [
        "dblclick",
        "#save",
    ]
    assert browser_act_args(
        "select",
        {"kind": "select", "selector": "#pet", "values": ["cat", "dog"]},
    ) == [
        "select",
        "#pet",
        "cat",
        "dog",
    ]
    assert browser_act_args("scroll", {"kind": "scroll", "direction": "down", "px": 400}) == [
        "scroll",
        "down",
        "400",
    ]
    assert browser_act_args(
        "scrollintoview",
        {"kind": "scrollintoview", "ref": "@hero"},
    ) == [
        "scrollintoview",
        "@hero",
    ]
    assert browser_act_args(
        "drag",
        {"kind": "drag", "source": "@card", "destination": "@dropzone"},
    ) == [
        "drag",
        "@card",
        "@dropzone",
    ]
    assert browser_act_args("mouse", {"kind": "mouse", "action": "move", "x": 15, "y": 30}) == [
        "mouse",
        "move",
        "15",
        "30",
    ]
    assert browser_act_args(
        "mouse",
        {"kind": "mouse", "action": "wheel", "dy": 120, "dx": -5},
    ) == [
        "mouse",
        "wheel",
        "120",
        "-5",
    ]
    assert browser_act_args(
        "keyboard",
        {"kind": "keyboard", "action": "inserttext", "text": "pasted content"},
    ) == [
        "keyboard",
        "inserttext",
        "pasted content",
    ]
    assert browser_act_args(
        "find",
        {
            "kind": "find",
            "locator": "role",
            "value": "button",
            "action": "click",
            "name": "Submit",
            "exact": True,
        },
    ) == [
        "find",
        "role",
        "button",
        "click",
        "--name",
        "Submit",
        "--exact",
    ]
    assert browser_act_args(
        "find",
        {
            "kind": "find",
            "locator": "label",
            "value": "Email",
            "action": "fill",
            "text": "user@example.com",
        },
    ) == [
        "find",
        "label",
        "Email",
        "fill",
        "user@example.com",
    ]


