        calls.append(invocation)
        if invocation[-4:-2] == ["set", "credentials"]:
            return Completed("credentials set for admin with secret-token")
        if invocation[-3:-1] == ["set", "headers"]:
            return Completed("headers set with Bearer token")
        return Completed()

