@pytest.mark.asyncio
async def test_node_pair_request_persists_and_refreshes_openclaw_pending_entries(
    tmp_path,
) -> None:
    database = Database(tmp_path / "data" / "openzues-test.db")
    await database.initialize()
    pairing_service = GatewayNodePairingService(database)
    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        pairing_service=pairing_service,
    )

    first = await service.call(
        "node.pair.request",
        {
            "nodeId": "pair-node-1",
            "displayName": "Builder Phone",
            "platform": "ios",
            "version": "1.2.3",
            "coreVersion": "2.0.0",
            "uiVersion": "3.0.0",
            "deviceFamily": "iphone",
            "modelIdentifier": "iphone15,3",
            "caps": ["voice", "canvas"],
            "commands": ["canvas.present"],
            "remoteIp": "10.0.0.5",
        },
        now_ms=1_000,
    )
    second = await service.call(
        "node.pair.request",
        {
            "nodeId": "pair-node-1",
            "displayName": "Builder Phone Updated",
            "platform": "ios",
            "version": "1.2.3",
            "coreVersion": "2.0.0",
            "uiVersion": "3.0.0",
            "deviceFamily": "iphone",
            "modelIdentifier": "iphone15,3",
            "caps": ["voice", "canvas"],
            "commands": ["canvas.present"],
            "remoteIp": "10.0.0.6",
            "silent": True,
        },
        now_ms=2_000,
    )
    pairing = await service.call("node.pair.list", {})

    assert first["status"] == "pending"
    assert first["created"] is True
    request_id = first["request"]["requestId"]
    assert first["request"] == {
        "requestId": request_id,
        "nodeId": "pair-node-1",
        "displayName": "Builder Phone",
        "platform": "ios",
        "version": "1.2.3",
        "coreVersion": "2.0.0",
        "uiVersion": "3.0.0",
        "deviceFamily": "iphone",
        "modelIdentifier": "iphone15,3",
        "caps": ["voice", "canvas"],
        "commands": ["canvas.present"],
        "remoteIp": "10.0.0.5",
        "ts": 1_000,
    }
    assert second == {
        "status": "pending",
        "request": {
            "requestId": request_id,
            "nodeId": "pair-node-1",
            "displayName": "Builder Phone Updated",
            "platform": "ios",
            "version": "1.2.3",
            "coreVersion": "2.0.0",
            "uiVersion": "3.0.0",
            "deviceFamily": "iphone",
            "modelIdentifier": "iphone15,3",
            "caps": ["voice", "canvas"],
            "commands": ["canvas.present"],
            "remoteIp": "10.0.0.6",
            "silent": True,
            "ts": 2_000,
        },
        "created": False,
    }
    assert pairing == {
        "pending": [
            {
                "requestId": request_id,
                "nodeId": "pair-node-1",
                "displayName": "Builder Phone Updated",
                "platform": "ios",
                "version": "1.2.3",
                "coreVersion": "2.0.0",
                "uiVersion": "3.0.0",
                "deviceFamily": "iphone",
                "modelIdentifier": "iphone15,3",
                "caps": ["voice", "canvas"],
                    "commands": ["canvas.present"],
                    "remoteIp": "10.0.0.6",
                    "silent": True,
                    "ts": 2_000,
                    "requiredApproveScopes": ["operator.pairing", "operator.write"],
                }
        ],
        "paired": [],
    }


