@pytest.mark.asyncio
@pytest.mark.parametrize(
    ("method", "decision"),
    [
        ("node.pair.approve", "approved"),
        ("node.pair.reject", "rejected"),
    ],
)
async def test_node_pair_resolution_broadcasts_openclaw_resolved_event(
    tmp_path,
    method: str,
    decision: str,
) -> None:
    database = Database(tmp_path / "data" / "openzues-test.db")
    await database.initialize()
    pairing_service = GatewayNodePairingService(database)
    hub = BroadcastHub()
    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        pairing_service=pairing_service,
        hub=hub,
    )
    requester = GatewayNodeMethodRequester(caller_scopes=("operator.pairing", "operator.admin"))

    created = await service.call(
        "node.pair.request",
        {
            "nodeId": f"pair-node-event-{decision}",
            "displayName": "Event Node",
            "platform": "macos",
            "commands": ["system.run"],
        },
        now_ms=1_000,
    )
    request_id = created["request"]["requestId"]

    async with hub.subscribe() as queue:
        if method == "node.pair.approve":
            await service.call(
                method,
                {"requestId": request_id},
                requester=requester,
                now_ms=2_000,
            )
        else:
            await service.call(
                method,
                {"requestId": request_id},
                now_ms=2_000,
            )
        broadcast = await asyncio.wait_for(queue.get(), timeout=1.0)

    assert broadcast["type"] == "gateway_event"
    assert broadcast["event"] == "node.pair.resolved"
    assert broadcast["payload"] == {
        "requestId": request_id,
        "nodeId": f"pair-node-event-{decision}",
        "decision": decision,
        "ts": 2_000,
    }
    assert isinstance(broadcast["createdAt"], str)


@pytest.mark.asyncio
async def test_node_pair_approve_verify_and_rename_lifecycle(tmp_path) -> None:
    database = Database(tmp_path / "data" / "openzues-test.db")
    await database.initialize()
    pairing_service = GatewayNodePairingService(database)
    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        pairing_service=pairing_service,
    )
    requester = GatewayNodeMethodRequester(caller_scopes=("operator.pairing", "operator.admin"))

    created = await service.call(
        "node.pair.request",
        {
            "nodeId": "pair-node-3",
            "displayName": "Approve Me",
            "platform": "macos",
            "commands": ["system.run"],
            "remoteIp": "10.0.0.9",
        },
        now_ms=1_000,
    )
    request_id = created["request"]["requestId"]

    approved = await service.call(
        "node.pair.approve",
        {"requestId": request_id},
        requester=requester,
        now_ms=2_000,
    )
    token = approved["node"]["token"]
    verified = await service.call(
        "node.pair.verify",
        {"nodeId": "pair-node-3", "token": token},
    )
    renamed = await service.call(
        "node.rename",
        {"nodeId": "pair-node-3", "displayName": "Renamed Node"},
    )
    pairing = await service.call("node.pair.list", {})

    assert approved == {
        "requestId": request_id,
        "node": {
            "nodeId": "pair-node-3",
            "token": token,
            "displayName": "Approve Me",
            "platform": "macos",
            "version": None,
            "coreVersion": None,
            "uiVersion": None,
            "deviceFamily": None,
            "modelIdentifier": None,
            "caps": [],
            "commands": ["system.run"],
            "remoteIp": "10.0.0.9",
            "permissions": None,
            "createdAtMs": 2_000,
            "approvedAtMs": 2_000,
            "lastConnectedAtMs": None,
        },
    }
    assert isinstance(token, str)
    assert len(token) == 43
    assert verified == {
        "ok": True,
        "node": {
            "nodeId": "pair-node-3",
            "token": token,
            "displayName": "Approve Me",
            "platform": "macos",
            "version": None,
            "coreVersion": None,
            "uiVersion": None,
            "deviceFamily": None,
            "modelIdentifier": None,
            "caps": [],
            "commands": ["system.run"],
            "remoteIp": "10.0.0.9",
            "permissions": None,
            "createdAtMs": 2_000,
            "approvedAtMs": 2_000,
            "lastConnectedAtMs": None,
        },
    }
    assert renamed == {
        "nodeId": "pair-node-3",
        "displayName": "Renamed Node",
    }
    assert pairing == {
        "pending": [],
        "paired": [
            {
                "nodeId": "pair-node-3",
                "token": token,
                "displayName": "Renamed Node",
                "platform": "macos",
                "version": None,
                "coreVersion": None,
                "uiVersion": None,
                "deviceFamily": None,
                "modelIdentifier": None,
                "caps": [],
                "commands": ["system.run"],
                "remoteIp": "10.0.0.9",
                "permissions": None,
                "createdAtMs": 2_000,
                "approvedAtMs": 2_000,
                "lastConnectedAtMs": None,
            }
        ],
    }


