@pytest.mark.asyncio
async def test_node_event_records_event_and_broadcasts_when_runtime_wired(tmp_path) -> None:
    database = Database(tmp_path / "node-event.db")
    await database.initialize()
    registry = GatewayNodeRegistry()
    _register_ios_node(registry)
    hub = BroadcastHub()
    requester = GatewayNodeMethodRequester(node_id="node-1")
    service = GatewayNodeMethodService(registry, database=database, hub=hub)

    async with hub.subscribe() as queue:
        response = await service.call(
            "node.event",
            {"event": "heartbeat", "payload": {"ok": True}},
            requester=requester,
        )
        broadcast = await asyncio.wait_for(queue.get(), timeout=1.0)

    events = await database.list_events()

    assert response == {"ok": True}
    assert len(events) == 1
    assert events[0]["instance_id"] is None
    assert events[0]["thread_id"] is None
    assert events[0]["method"] == "node.event"
    assert events[0]["payload"]["nodeId"] == "node-1"
    assert events[0]["payload"]["event"] == "heartbeat"
    assert events[0]["payload"]["payload"] == {"ok": True}
    assert json.loads(events[0]["payload"]["payloadJSON"]) == {"ok": True}

    assert broadcast["type"] == "node_event"
    assert broadcast["nodeId"] == "node-1"
    assert broadcast["event"] == "heartbeat"
    assert broadcast["payload"] == {"ok": True}
    assert json.loads(str(broadcast["payloadJSON"])) == {"ok": True}
    assert isinstance(broadcast["createdAt"], str)


@pytest.mark.asyncio
async def test_node_event_chat_subscribe_routes_session_events_to_node(tmp_path) -> None:
    database = Database(tmp_path / "node-event-chat-subscribe.db")
    await database.initialize()
    registry = GatewayNodeRegistry()
    connection = FakeNodeConnection("conn-node-chat-subscribe")
    registry.register(
        connection,
        GatewayNodeConnect(
            client_id="live-node-chat-subscribe",
            device_id="node-chat-subscribe",
            client_mode="mobile",
            display_name="Subscriber Phone",
            platform="ios",
            caps=("voice", "canvas"),
            commands=("canvas.present",),
        ),
        connected_at_ms=321,
    )
    service = GatewayNodeMethodService(registry, database=database, hub=BroadcastHub())
    requester = GatewayNodeMethodRequester(node_id="node-chat-subscribe")

    response = await service.call(
        "node.event",
        {
            "event": "chat.subscribe",
            "payload": {"sessionKey": "agent:main:main"},
        },
        requester=requester,
    )
    sent_count = registry.send_to_session(
        "agent:main:main",
        "chat",
        {"sessionKey": "agent:main:main", "state": "delta"},
    )

    assert response == {"ok": True}
    assert sent_count == 1
    assert connection.sent_events[-1] == {
        "event": "chat",
        "payload": {"sessionKey": "agent:main:main", "state": "delta"},
    }

    response = await service.call(
        "node.event",
        {
            "event": "chat.unsubscribe",
            "payloadJSON": '{"sessionKey": "agent:main:main"}',
        },
        requester=requester,
    )
    sent_count = registry.send_to_session(
        "agent:main:main",
        "chat",
        {"sessionKey": "agent:main:main", "state": "final"},
    )

    assert response == {"ok": True}
    assert sent_count == 0
    assert connection.sent_events[-1] == {
        "event": "chat",
        "payload": {"sessionKey": "agent:main:main", "state": "delta"},
    }


