@pytest.mark.asyncio
async def test_push_test_clears_stale_direct_apns_registration_on_bad_device_token(
    tmp_path,
) -> None:
    database = Database(tmp_path / "node-event-apns-stale-token.db")
    await database.initialize()
    registry = GatewayNodeRegistry()
    _register_ios_node(registry)
    send_calls: list[dict[str, object]] = []

    async def fake_apns_sender(
        *,
        node_id: str,
        registration: dict[str, object],
        title: str,
        body: str,
        environment: str | None,
    ) -> dict[str, object]:
        del node_id, title, body, environment
        send_calls.append(dict(registration))
        return {
            "ok": False,
            "status": 400,
            "reason": "BadDeviceToken",
            "transport": "direct",
        }

    service = GatewayNodeMethodService(
        registry,
        database=database,
        hub=BroadcastHub(),
        send_apns_push_service=fake_apns_sender,
    )
    requester = GatewayNodeMethodRequester(node_id="node-1")

    await service.call(
        "node.event",
        {
            "event": "push.apns.register",
            "payload": {
                "transport": "direct",
                "token": "c" * 64,
                "topic": "com.openzues.ios",
                "environment": "sandbox",
            },
        },
        requester=requester,
    )

    result = await service.call("push.test", {"nodeId": "node-1"})

    assert result == {
        "ok": False,
        "status": 400,
        "reason": "BadDeviceToken",
        "transport": "direct",
    }
    with pytest.raises(GatewayNodeMethodError, match="has no APNs registration"):
        await service.call("push.test", {"nodeId": "node-1"})
    assert send_calls == [
        {
            "transport": "direct",
            "token": "c" * 64,
            "topic": "com.openzues.ios",
            "environment": "sandbox",
        }
    ]


@pytest.mark.asyncio
async def test_system_event_records_event_and_broadcasts_presence_snapshot(tmp_path) -> None:
    database = Database(tmp_path / "system-event.db")
    await database.initialize()
    registry = GatewayNodeRegistry()
    _register_ios_node(registry)
    hub = BroadcastHub()
    service = GatewayNodeMethodService(
        registry,
        database=database,
        hub=hub,
        gateway_identity_service=GatewayIdentityService(tmp_path),
    )

    async with hub.subscribe() as queue:
        response = await service.call(
            "system-event",
            {
                "text": "note from test",
                "deviceId": "device-1",
                "instanceId": "instance-1",
                "roles": ["operator", "operator", "  "],
                "tags": ["gateway", "test"],
            },
            now_ms=1_700_000_000_000,
        )
        broadcast = await asyncio.wait_for(queue.get(), timeout=1.0)

    events = await database.list_events()

    assert response == {"ok": True}
    assert len(events) == 1
    assert events[0]["instance_id"] is None
    assert events[0]["thread_id"] is None
    assert events[0]["method"] == "system-event"
    assert events[0]["payload"] == {
        "text": "note from test",
        "deviceId": "device-1",
        "instanceId": "instance-1",
        "roles": ["operator"],
        "tags": ["gateway", "test"],
    }

    assert broadcast["type"] == "gateway_event"
    assert broadcast["event"] == "presence"
    assert isinstance(broadcast["createdAt"], str)
    assert "presence" in broadcast["payload"]
    assert isinstance(broadcast["payload"]["presence"], list)
    node_entry = next(
        entry for entry in broadcast["payload"]["presence"] if entry.get("deviceId") == "node-1"
    )
    assert node_entry["host"] == "Builder Phone"
    self_entry = next(
        entry for entry in broadcast["payload"]["presence"] if entry.get("reason") == "self"
    )
    assert re.fullmatch(r"[0-9a-f]{64}", self_entry["deviceId"])


