@pytest.mark.asyncio
async def test_send_uses_channel_message_runtime_and_derives_thread_from_session_key() -> None:
    source_session_key = resolve_thread_session_keys(
        base_session_key=build_launch_session_key(
            mode="workspace_affinity",
            preferred_instance_id=None,
            task_id=None,
            project_id=None,
            operator_id=None,
            conversation_target=ConversationTargetView(
                channel="slack",
                peer_kind="channel",
                peer_id="channel:C123",
            ),
        ),
        thread_id="1710000000.9999",
    ).session_key
    expected_target_session_key = (
        "launch:mode:workspace_affinity:channel:slack:peer:channel:"
        "channel:c123:thread:1710000000.9999"
    )
    calls: list[dict[str, object | None]] = []

    async def fake_send_channel_message_service(
        *,
        channel: str,
        to: str,
        message: str,
        account_id: str | None,
        agent_id: str | None,
        thread_id: str | None,
        session_key: str | None,
        idempotency_key: str,
    ) -> dict[str, object]:
        calls.append(
            {
                "channel": channel,
                "to": to,
                "message": message,
                "account_id": account_id,
                "agent_id": agent_id,
                "thread_id": thread_id,
                "session_key": session_key,
                "idempotency_key": idempotency_key,
            }
        )
        return {
            "ok": True,
            "messageId": "42",
            "sessionKey": expected_target_session_key,
            "deliveryId": 7,
        }

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        send_channel_message_service=fake_send_channel_message_service,
    )

    payload = await service.call(
        "send",
        {
            "to": " channel:C123 ",
            "message": "Ship parity.",
            "channel": "slack",
            "accountId": "   ",
            "agentId": "   ",
            "threadId": "   ",
            "sessionKey": source_session_key,
            "idempotencyKey": "idem-send-runtime",
        },
    )

    assert calls == [
        {
            "channel": "slack",
            "to": "channel:C123",
            "message": "Ship parity.",
            "account_id": None,
            "agent_id": None,
            "thread_id": "1710000000.9999",
            "session_key": source_session_key,
            "idempotency_key": "idem-send-runtime",
        }
    ]
    assert payload == {
        "ok": True,
        "messageId": "42",
        "sessionKey": expected_target_session_key,
        "deliveryId": 7,
    }


@pytest.mark.asyncio
async def test_send_uses_resolved_subagent_store_key_for_delivery_provenance() -> None:
    tmp_path = Path.cwd() / ".tmp-pytest-local" / "gateway-send-subagent-alias"
    shutil.rmtree(tmp_path, ignore_errors=True)
    tmp_path.mkdir(parents=True, exist_ok=True)
    database = Database(tmp_path / "gateway-send-subagent-alias.db")
    await database.initialize()
    resolved_session_key = "agent:main:subagent:child"
    await database.upsert_gateway_session_metadata(
        session_key=resolved_session_key,
        metadata={"label": "Child Session"},
    )
    calls: list[dict[str, object | None]] = []

    async def fake_send_channel_message_service(
        *,
        channel: str,
        to: str,
        message: str,
        account_id: str | None,
        agent_id: str | None,
        thread_id: str | None,
        session_key: str | None,
        idempotency_key: str,
    ) -> dict[str, object]:
        calls.append(
            {
                "channel": channel,
                "to": to,
                "message": message,
                "account_id": account_id,
                "agent_id": agent_id,
                "thread_id": thread_id,
                "session_key": session_key,
                "idempotency_key": idempotency_key,
            }
        )
        return {"ok": True, "messageId": "43", "sessionKey": session_key, "deliveryId": 8}

    service = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        database=database,
        sessions_service=GatewaySessionsService(database),
        send_channel_message_service=fake_send_channel_message_service,
    )

    payload = await service.call(
        "send",
        {
            "to": " channel:C123 ",
            "message": "Ship child parity.",
            "channel": "slack",
            "sessionKey": "subagent:child",
            "idempotencyKey": "idem-send-subagent-runtime",
        },
    )

    assert calls == [
        {
            "channel": "slack",
            "to": "channel:C123",
            "message": "Ship child parity.",
            "account_id": None,
            "agent_id": None,
            "thread_id": None,
            "session_key": resolved_session_key,
            "idempotency_key": "idem-send-subagent-runtime",
        }
    ]
    assert payload == {
        "ok": True,
        "messageId": "43",
        "sessionKey": resolved_session_key,
        "deliveryId": 8,
    }


