@pytest.mark.asyncio
async def test_node_invoke_uses_recorded_apns_wake_when_saved_lane_wake_is_unavailable(
    tmp_path,
) -> None:
    database = Database(tmp_path / "node-invoke-apns-wake.db")
    await database.initialize()
    registry = GatewayNodeRegistry()
    registry.remember(
        KnownNode(
            node_id="ios-node-1",
            display_name="iOS Wakeable Node",
            platform="ios",
            client_id="ios-node-1",
            client_mode="ios",
            commands=("system.notify",),
            paired=True,
            connected=False,
        )
    )
    await database.append_event(
        instance_id=None,
        thread_id=None,
        method="node.event",
        payload={
            "nodeId": "ios-node-1",
            "event": "push.apns.register",
            "payload": {
                "transport": "relay",
                "relayHandle": "relay-handle-123",
                "sendGrant": "relay-send-grant-123",
                "installationId": "install-123",
                "topic": "com.openzues.ios",
                "environment": "production",
                "distribution": "official",
            },
        },
    )
    wake_calls: list[dict[str, object]] = []

    async def fake_apns_wake(
        *,
        node_id: str,
        registration: dict[str, object],
        wake_reason: str,
    ) -> dict[str, object]:
        wake_calls.append(
            {
                "node_id": node_id,
                "registration": registration,
                "wake_reason": wake_reason,
            }
        )
        asyncio.get_running_loop().call_soon(
            lambda: registry.register(
                AutoReplyNodeConnection(registry, "conn-ios-node-1"),
                GatewayNodeConnect(
                    client_id="ios-node-1",
                    device_id=node_id,
                    client_mode="ios",
                    display_name="iOS Wakeable Node",
                    platform="ios",
                    commands=("system.notify",),
                ),
            )
        )
        return {
            "attempted": True,
            "available": True,
            "connected": False,
            "path": "sent",
            "durationMs": 3,
        }

    service = GatewayNodeMethodService(
        registry,
        database=database,
        send_apns_wake_service=fake_apns_wake,
    )

    result = await service.call(
        "node.invoke",
        {
            "nodeId": "ios-node-1",
            "command": "system.notify",
            "params": {"title": "Wake", "body": "Reconnect."},
            "timeoutMs": 250,
            "idempotencyKey": "idem-apns-wake",
        },
    )

    assert result == {
        "ok": True,
        "nodeId": "ios-node-1",
        "command": "system.notify",
        "payload": {"status": "done"},
        "payloadJSON": '{"status":"done"}',
    }
    assert wake_calls == [
        {
            "node_id": "ios-node-1",
            "registration": {
                "transport": "relay",
                "relayHandle": "relay-handle-123",
                "sendGrant": "relay-send-grant-123",
                "installationId": "install-123",
                "topic": "com.openzues.ios",
                "environment": "production",
                "distribution": "official",
            },
            "wake_reason": "node.invoke",
        }
    ]


